def validate_drawio(content: str) -> ET.Element:
    root = ET.fromstring(content)
    diagrams = root.findall("diagram")
    errors: list[str] = []

    if len(diagrams) != EXPECTED_DIAGRAMS:
        errors.append(f"expected {EXPECTED_DIAGRAMS} diagrams, found {len(diagrams)}")

    for diagram in diagrams:
        name = diagram.attrib.get("name", "<unnamed>")
        model = diagram.find("mxGraphModel")
        if model is None:
            errors.append(f"{name}: missing mxGraphModel")
            continue
        root_node = model.find("root")
        if root_node is None:
            errors.append(f"{name}: missing root node")
            continue
        if not root_node.findall("mxCell"):
            errors.append(f"{name}: contains no mxCell elements")

    if errors:
        joined = "\n".join(f"- {error}" for error in errors)
        raise ValueError(f"Draw.io validation failed:\n{joined}")
    return root


def write_drawio(output_path: Path, *, strict_validation: bool) -> None:
    content = SAVED_DRAWIO_XML
    if strict_validation:
        validate_drawio(content)
    else:
        try:
            validate_drawio(content)
        except ValueError as exc:
            print(f"Warning: {exc}")

    output_path.parent.mkdir(parents=True, exist_ok=True)
    output_path.write_text(content, encoding="utf-8")
    root = ET.fromstring(content)
    print(f"Done. Wrote {len(content):,} chars to {output_path}")
    print(f"Diagrams: {len(root.findall('diagram'))}")


def parse_args() -> argparse.Namespace:
    parser = argparse.ArgumentParser(description="Write saved cascDP architecture.drawio")
    parser.add_argument(
        "--output",
        type=Path,
        default=DEFAULT_OUTPUT,
        help=f"Output .drawio path (default: {DEFAULT_OUTPUT})",
    )
    parser.add_argument(
        "--strict-validation",
        action="store_true",
        help="Fail if the embedded draw.io XML is structurally invalid.",
    )
    return parser.parse_args()


def main() -> None:
    args = parse_args()
    write_drawio(args.output, strict_validation=args.strict_validation)


if __name__ == "__main__":
    main()
